# Helper functions to load and save data

def load_properties():
    properties = []
    with open(PROPERTIES_FILE, 'r') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            # format: id|location|price|type|beds|baths|sqft|description
            parts = line.split('|')
            if len(parts) != 8:
                continue
            prop = {
                'id': parts[0],
                'location': parts[1],
                'price': int(parts[2]),
                'type': parts[3],
                'beds': int(parts[4]),
                'baths': float(parts[5]),
                'sqft': int(parts[6]),
                'description': parts[7]
            }
            properties.append(prop)
    return properties

def save_properties(properties):
    with open(PROPERTIES_FILE, 'w') as f:
        for p in properties:
            line = '|'.join([str(p['id']), p['location'], str(p['price']), p['type'], str(p['beds']), str(p['baths']), str(p['sqft']), p['description']])
            f.write(line + '\n')

