    save_favorites(favorites)
    return redirect(url_for('favorites_page'))

@app.route('/submit-inquiry', methods=['POST'])
def submit_inquiry():
    # Fields: property_id, customer_name, customer_email, customer_phone, message
    property_id = request.form.get('select-property')
    customer_name = request.form.get('inquiry-name')
    customer_email = request.form.get('inquiry-email')
    customer_phone = request.form.get('inquiry-phone')
    message = request.form.get('inquiry-message')

    if not all([property_id, customer_name, customer_email, customer_phone]):
        return "Missing required fields", 400

    inquiries = load_inquiries()
    new_inquiry = {
        'inquiry_id': generate_id(),
        'property_id': property_id,
        'customer_name': customer_name,
        'customer_email': customer_email,
        'customer_phone': customer_phone,
        'message': message or '',
        'status': 'Pending',
        'date': ''  # Could be set to current date if needed
    }
    inquiries.append(new_inquiry)
    save_inquiries(inquiries)
    return redirect(url_for('inquiries_page'))

@app.route('/delete-inquiry/<inquiry_id>', methods=['POST'])
def delete_inquiry(inquiry_id):
    inquiries = load_inquiries()
    inquiries = [inq for inq in inquiries if inq['inquiry_id'] != inquiry_id]
    save_inquiries(inquiries)
    return redirect(url_for('inquiries_page'))

@app.route('/contact-agent/<agent_id>')
